INSERT INTO covenants (id, name, aura_type, aura_level, founding_year, tribunal, size, description, is_official, domus_magna, season_status, location_desc, gps_coords, notable_magi, custodes, grogs_desc, vis_sources, laboratories, library)
VALUES 
('cov-durenmar-0000', 'Durenmar', 'magic', 5, 767, 'Rhine', 'medium', 'Le berceau historique de l''Ordre, fondé par Bonisagus et Trianoma. C''est une immense structure mi-forteresse mi-monastère en pierre de taille, faisant office de centre de gouvernance spirituelle et intellectuelle pour l''ensemble des mages d''Hermès.', 1, 'Maison Bonisagus', 'Automne', 'Nichée au plus profond de la haute Forêt Noire, entourée de vallées brumeuses et de chênes millénaires (Bade-Wurtemberg, Allemagne actuelle).', '48.0100° N, 8.1500° E', 'Prima Murion (Dirigeante de la Maison Bonisagus), Archimage Lucas (Théoricien du Vim), et une quinzaine de chercheurs érudits résidents.', 'Le Collège des Scribes : un ensemble impressionnant d''érudits mondains, de maîtres linguistes, de paléographes et de copistes traduisant les manuscrits antiques grecs, hébreux et arabes.', 'Le Turb de Durenmar : une force militaire lourde et hautement entraînée, équipée de cottes de mailles d''excellente facture, patrouillant sans relâche les lisières forestières et protégeant les convois de livres sacrés.', 'La Clairière des Échos (10 pions Vim), Les Cavernes de Cristal (8 pions Creo), Les Rapaces de la Forêt Noire (8 pions Animal), Les Chênes de Bonisagus (6 pions Herbam).', 'Salles monumentales en pierre de taille. Ils possèdent presque tous la Vertu structurelle Grande Bibliothèque Connectée, offrant un bonus de +3 aux jets de Recherche et de Théorie Magique. Le laboratoire de la Prima Murion dispose d''installations uniques dédiées spécifiquement à l''Expérimentation Hermétique.', 'La Grande Bibliothèque de Durenmar est la plus monumentale de l''Ordre. Elle renferme les parchemins originaux des Fondateurs. Elle compte plus de 80 Summae de niveau exceptionnel (scores allant jusqu''à 25) couvrant l''intégralité des 15 Arts, et des milliers de Tractatus.'),
('cov-fengheld-0000', 'Fengheld', 'magic', 5, 865, 'Rhine', 'medium', 'Un château fortifié imposant qui incarne la faction conservatrice et politiquement active du Rhin. Siège de la puissante Guilde de l''Appeau, Fengheld gère ses relations avec le monde mondain comme une véritable baronnie autonome.', 1, NULL, 'Automne', 'Érigée sur un promontoire rocheux fortifié dominant de manière spectaculaire la vallée de la Moselle, à proximité de Trèves (Allemagne actuelle).', '49.8167° N, 6.4167° E', 'Archimage Stentorius (Tremere, figure politique majeure du tribunal), Horst (Mercere), Eule (Bjornaer).', 'Régisseurs domaniaux, intendants économiques et maires de villages mondains gérant les vastes baux agricoles et les transactions de l''alliance.', 'Une garnison permanente de 50 soldats de métier en livrée rouge et noire, experts en défense de remparts et en escorte de marchands.', 'Les Vignes de la Moselle (12 pions Herbam), Les Sables de la Moselle (6 pions Terram), L''Autel de la Guilde (4 pions Vim).', 'Ateliers spacieux, fortifiés, orientés vers la sécurité architecturale. Ils intègrent souvent la Vertu Défenses Renforcées et des protections contre l''espionnage invisible, adaptées aux mages impliqués dans les conflits politiques.', 'Une collection de premier choix axée sur le droit hermétique, la diplomatie, la politique des tribunaux et l''Art du Terram. Contient les arbres généalogiques de la noblesse locale et les chartes de la majorité des alliances du Rhin.'),
('cov-crintera-0000', 'Crintera', 'magic', 5, 772, 'Rhine', 'medium', 'Un lieu sauvage et mystique, dénué de structures hermétiques classiques en pierre. L''alliance est composée de sanctuaires arboricoles, de tentes de peau et de cavernes côtières, reflétant le refus de la Maison Bjornaer de se couper de la nature sauvage.', 1, 'Maison Bjornaer', 'Automne', 'Le long des falaises de craie blanche et dans les forêts primitives de l''Île de Rügen, dans la Mer Baltique (Allemagne actuelle).', '54.4167° N, 13.4167° E', 'Prima Falke (Bjornaer, changeuse de forme en faucon pèlerin) et le Conseil des Anciens de la Chasse.', 'Pratiquement aucun humain mondain. Les rares compagnons admis sont des changeurs de forme mineurs, des bêtes éveillées ou des chamans sylvestres.', 'Absence totale de troupes humaines conventionnelles. La défense de l''île est assurée par des meutes de loups gris et d''ours bruns doués de capacités magiques mineures.', 'Les Falaises de Craie (8 pions Muto), Le Sanctuaire des Meutes (8 pions Animal), L''Ambre de la Baltique (4 pions Herbam).', 'Aménagés dans des grottes naturelles ou au cœur d''arbres creux titanesques. Ils possèdent le Défaut Sans Confort pour les humains, mais bénéficient de la Vertu Résonance Animale, octroyant un bonus de +2 pour l''étude et le développement de sorts liés aux créatures vivantes.', 'Une collection atypique, consignée sur des peaux tannées ou des écorces de bouleau gravées. Elle est entièrement consacrée aux Mystères de la Maison, à la magie sensorielle, à l''art du Muto et de l''Animal.'),
('cov-irencilia-0000', 'Irencilia', 'faerie', 6, 802, 'Rhine', 'medium', 'Un domaine onirique où l''architecture semble vivante, tressée à partir d''arbres et de lianes lumineuses. Le temps s''y s''écoule différemment, et l''alliance semble exister à la frontière exacte entre l''Europe Mythique et Arcadia.', 1, 'Maison Merinita', 'Automne (Féerique)', 'Établie dans une clairière mouvante et dissimulée au cœur des forêts denses de Bavière (Allemagne actuelle).', '47.9000° N, 11.5000° E', 'Primus Handen (Merinita, expert des pactes faës) et de nombreux mages illusionnistes de renom.', 'Conteurs de légendes, ménestrels, troubadours, poètes touchés par la féerie et émissaires de la Cour Féerique locale.', 'Structure militaire conventionnelle inexistante. La protection de la clairière repose sur des barrières d''illusions massives déroutant les intrus et sur des créatures féeriques liées par d''anciens pactes.', 'La Fontaine aux Souhaits (8 pions Imaginem), Les Champignons de Sabbat (6 pions Mentem), Les Brumes d''Irencilia (4 pions Auram).', 'Salles sylvestres ouvertes sur le ciel, ornées de plantes bioluminescentes. Équipés de la Vertu Touché par la Féerie, conférant un bonus pour la création d''illusions et de charmes, mais augmentant les risques de manifestations bizarres.', 'Collection de parchemins soyeux regroupant des pièces de théâtre féerique, des recueils d''illusions (Imaginem) et des grimoires uniques détaillant l''histoire et la psychologie des Faës.'),
('cov-fudarus-0000', 'Fudarus', 'magic', 5, 767, 'Normandy', 'medium', 'Une forteresse austère, sombre et impitoyable. C''est le centre mondial des intrigues et des défis de la Maison Tytalus, où chaque apprenti et mage doit constamment lutter contre ses pairs pour prouver sa force et sa supériorité intellectuelle.', 1, 'Maison Tytalus', 'Automne', 'Une île rocheuse fortifiée et escarpée, balayée par les vents violents au large du cap de la Hague, Cotentin (Normandie, France).', '49.6500° N, -1.8500° E', 'La Prima de la Maison Tytalus et son conseil de maîtres des jeux d''esprit et du conflit.', 'Tacticiens militaires, maîtres-espions mondains, assassins de l''ombre et intendants rompus aux manipulations politiques complexes.', 'Marins endurcis et gardes d''élite soumis par les mages à des épreuves psychologiques et physiques sadiques pour éliminer toute trace de faiblesse ou de pitié.', 'Les Récifs Noirs (8 pions Auram), Le Cimetière des Naufrages (6 pions Perdo), La Tour des Cris (4 pions Mentem).', 'Creusés à même la roche de la falaise, ces laboratoires sont sombres, humides et isolés. Beaucoup possèdent le Défaut Sombre ou Humide, mais ils compensent par la Vertu Laboratoire Secret et des systèmes complexes de pièges magiques pour protéger les recherches contre l''espionnage de leurs propres confrères.', 'Une vaste collection de traités de psychologie, d''art de la guerre, de grimoires avancés de Mentem et d''Imaginem, ainsi que des dossiers de chantage cryptés sur la haute noblesse d''Europe.'),
('cov-levrier-0000', 'La Maison du Lévrier', 'magic', 4, 1150, 'Normandy', 'medium', 'Une grande et belle demeure seigneuriale entourée de jardins soignés. Cette alliance incarne la résistance face à l''hégémonie de Fudarus, refusant le système de vassalité hermétique normand et prônant une intégration harmonieuse et juste avec le monde laïque.', 1, NULL, 'Été', 'Dissimulée au sein d''un riche domaine forestier géré de manière autonome dans l''arrière-pays normand (Orne, France actuelle).', '48.6000° N, 0.1000° E', 'Prospero (Jerbiton, diplomate de renom auprès de la cour ducale), et une coterie de mages indépendants.', 'Artisans verriers, forgerons d''élite, architectes et érudits laïques administrant le domaine comme une seigneurie modèle et prospère.', 'Un Turb loyal et parfaitement équipé d''arcs longs et d''épées bâtardes, entraîné spécifiquement à détecter et intercepter les agents d''infiltration et les espions Tytalus.', 'La Source du Lévrier (6 pions Creo), Le Verger Magique (5 pions Herbam), Les Ruches d''Or (3 pions Animal).', 'Conçus comme des cabinets d''études clairs et aérés. Équipés de la Vertu Confort Élevé et de Matériel d''Excellence, favorisant le travail de laboratoire calme, l''écriture de traités et la création d''objets d''art magiques subtils.', 'Magnifique collection de manuscrits enluminés d''art classique, de philosophie aristotélicienne, de théologie et de Summae de haut niveau en Creo, Herbam et Imaginem.'),
('cov-exspectatio-0000', 'Exspectatio', 'magic', 4, 1050, 'Normandy', 'medium', 'Un avant-poste fortifié servant de terrain d''entraînement direct pour la Maison Tytalus. C''est une alliance vassale de Fudarus, où de jeunes mages ambitieux doivent faire leurs preuves dans la gestion des conflits de frontière avant d''espérer siéger à la maison-mère.', 1, NULL, 'Printemps / Été', 'Perchée sur les falaises maritimes marquant la frontière rocheuse entre la Normandie et la Bretagne (France).', '48.6333° N, -1.5167° E', 'Iasper (Jeune Tytalus ambitieux et agressif) et deux compagnons de laboratoire.', 'Pisteurs côtiers, contrebandiers locaux et passeurs maritimes gérant les contacts et frictions avec la petite noblesse bretonne.', 'Une garnison de 20 mercenaires habitués aux coups de main, à la piraterie discrète et aux escarmouches de frontière.', 'Les Grottes de la Marée (5 pions Aquam), Le Nid des Tempêtes (4 pions Auram), Les Galets Gravés (3 pions Rego).', 'Cellules spartiates aménagées dans les niveaux supérieurs de la tour de garde. Ils possèdent le Défaut Étroit mais bénéficient de la Vertu Vue sur la Mer, ce qui octroie un bonus pour l''étude des forces maritimes et météorologiques.', 'Bibliothèque modeste mais en pleine expansion, axée sur la cartographie maritime, les forces météorologiques (Auram) et l''art de la guerre navale.'),
('cov-doissetep-0000', 'Doissetep', 'magic', 6, 853, 'Provençal', 'large', 'Une forteresse colossale taillée directement dans la montagne noire. Reconnue pour sa puissance brute terrifiante, Doissetep est le théâtre permanent de rivalités acharnées entre factions de mages de guerre, faisant d''elle un géant politique instable.', 1, NULL, 'Automne', 'Sur les cimes rocheuses escarpées et inaccessibles des Pyrénées centrales (Côté nord, France actuelle).', '42.8000° N, 0.5000° E', 'Dominée historiquement par de puissants maîtres de guerre de la Maison Flambeau et des opportunistes politiques de la Maison Tremere.', 'Diplomates fins, intendants corrompus, majordomes de haut rang et espions infiltrés surveillant constamment les faits et gestes des mages.', 'Un Turb massif et redoutable composé de mercenaires d''élite équipés d''armes lourdes et d''armures enchantées pour résister au feu et aux sorts de destruction.', 'La Fissure de Feu (12 pions Ignem), Le Gouffre du Néant (8 pions Perdo), Les Cristaux de Soufre (8 pions Muto).', 'Véritables bunkers magiques hautement fortifiés. Équipés de la Vertu Taille Monumentale et de Protections Élémentaires, permettant de contenir les explosions accidentelles lors de l''invention de sorts de destruction de masse.', 'Collection colossale mais jalousement gardée par sections de factions. Elle est axée sur la magie élémentaire (Ignem/Auram), la destruction brute (Perdo) et les rituels de combat de masse.'),
('cov-valnegra-0000', 'Val-Negra', 'magic', 5, 773, 'Provençal', 'medium', 'Jadis le phare glorieux de la guerre contre les Maures et les Diedne, Val-Negra n''est plus que l''ombre d''elle-même. C''est une citadelle grise, partiellement en ruine, habitée par mages vieillissants figés dans la nostalgie et la paranoïa.', 1, 'Ancienne Maison Flambeau', 'Hiver', 'Une forteresse austère et sombre dissimulée dans les hautes vallées reculées des Pyrénées espagnoles.', '42.5000° N, 0.0000° E', 'Berengarius (Flambeau, vétéran centenaire couvert de cicatrices), et une poignée de mages isolationnistes.', 'Quelques érudits austères, vieux serviteurs brisés et gardiens de reliques de guerre vivant en autarcie totale.', 'Vétérans fanatiques, balafrés et méfiants, derniers remparts d''un bastion autrefois invincible, patrouillant dans des couloirs vides.', 'Les Cendres du Bastion (6 pions Ignem), La Crypte des Héros (4 pions Perdo).', 'Salles froides et délabrées. Présentent les Défauts Humide, Courants d''Air et Ancien, ce qui pénalise la recherche moderne, bien qu''ils conservent des bonus historiques pour l''enchantement d''épées de feu.', 'Riche en récits historiques sur la Reconquista et la Guerre du Schisme, mais la majorité des grimoires théoriques récents manquent à l''appel, rendant l''étude académique difficile.'),
('cov-harco-0000', 'Harco', 'magic', 3, 767, 'Rome', 'large', 'Le centre névralgique des communications et de l''économie de l''Ordre. Conçue comme un palais romain classique avec des thermes et des jardins, Harco coordonne le réseau mondial des Toques Rouges et sert de banque centrale informelle pour les transactions de Vis.', 1, 'Maison Mercere', 'Automne', 'Une somptueuse villa fortifiée d''architecture romaine le long de la Via Appia, à quelques milles au sud de Rome (Italie).', '41.8000° N, 12.6000° E', 'Prima Bilera (Mercere), entourée par le haut conseil des Toques Rouges.', 'Le cœur du réseau mondial des Toques Rouges (Redcaps) : marchands de soie, banquiers, juristes fins, et messagers non-éveillés d''une loyauté et d''une efficacité redoutables.', 'Gardes de caravanes d''élite, experts en contre-embuscade, en protection rapprochée en milieu urbain et en discrétion absolue plutôt qu''en guerre ouverte.', 'Les Sceaux de Cire (8 pions Vim), Les Bornes de la Via Appia (5 pions Rego), Les Pièces d''Or d''Harco (3 pions Mentem).', 'Cabinets d''études luxueux intégrés dans la villa. Équipés de la Vertu Confort Exceptionnel et Réseau d''Information, optimisés pour la création d''objets facilitant le transport, la téléportation ou la communication à distance.', 'Contient la plus grande collection de cartes géographiques d''Europe, d''histoires des familles nobles mondaines, dictionnaires de langues mortes et traités de Rego appliqués au déplacement.'),
('cov-verdi-0000', 'Verdi', 'magic', 5, 767, 'Rome', 'large', 'Le sanctuaire suprême de l''artisanat magique. Verdi est un complexe industriel et magique composé de fonderies, d''ateliers de joaillerie et de forges monumentales où les mages Verditus conçoivent les plus puissants artefacts de l''Europe Mythique.', 1, 'Maison Verditus', 'Automne', 'Dissimulée au fond d''une vallée rocheuse aride et isolée du massif du Gennargentu, sur l''île de Sardaigne (Italie).', '40.1200° N, 9.0100° E', 'Primus Stentorius (Verditus) et les plus talentueux (et vaniteux) artisans forge-sorts de l''Ordre.', 'Maîtres forgerons mondains, fondeurs de bronze, joailliers d''élite, mineurs et ingénieurs mécaniques liés par des contrats magiques drastiques.', 'Gardes statiques d''ateliers et de coffres-forts, lourdement armés, experts en contre-infraction et en détection des systèmes de vol ou d''invisibilité.', 'La Veine d''Orichalque (12 pions Terram), La Forge de Vulcain (10 pions Ignem).', 'Véritables forges magiques industrielles. Équipés des Vertus Fourneau d''Exception, Outils d''Artisan Supérieurs et Puits de Coulée Magique, conférant des bonus massifs (+5) pour la création d''enchantements permanents et d''artefacts métalliques ou minéraux.', 'Orientée exclusivement vers l''art de la forge, l''architecture, la métallurgie magique, l''alchimie et l''introduction d''esprits dans la matière inanimée. Les secrets de fabrication Verditus y sont jalousement cadenassés sous verrous magiques.'),
('cov-valnastium-0000', 'Valnastium', 'magic', 5, 798, 'Greater Alps', 'medium', 'Conçue comme un somptueux palais de la Renaissance avant l''heure, Valnastium est dédiée à la beauté, à la philosophie, aux arts classiques et aux belles-lettres. C''est le pont culturel entre l''Ordre d''Hermès et l''élite intellectuelle mondaine.', 1, 'Maison Jerbiton', 'Automne', 'Une vallée idyllique isolée, protégée du climat rigoureux par des barrières naturelles et magiques, dans l''Oberland bernois (Suisse).', '46.5500° N, 8.0200° E', 'Primus Andru (Jerbiton, esthète, philosophe et diplomate), et des mages artistes de premier plan.', 'Poètes, peintres humanistes, musiciens, sculpteurs de marbre et traducteurs d''œuvres classiques grecques et latines invités à demeure.', 'Une garde d''apparat en livrée de soie élégante, mais solidement formée aux tactiques militaires de montagne pour verrouiller les rares cols alpins menant à la vallée.', 'La Cascade de la Nymphe de Glace (7 pions Imaginem), La Roseraie de Valnastium (5 pions Creo), Les Larmes d''Andru (3 pions Mentem).', 'Conçus comme de magnifiques cabinets de réflexion princiers ou des ateliers d''artistes. Ils possèdent tous les Vertus Belle Vue (donnant sur les sommets enneigés), Confort Élevé et Galerie d''Art Intégrée, favorisant l''invention de sorts subtils et d''illusions pures.', 'Un chef-d''œuvre de calligraphie et d''enluminure. Contient des collections monumentales de philosophie classique, d''histoire romaine, de poésie courtoise et des Summae d''Imaginem et de Mentem d''une clarté littéraire inégalée.'),
('cov-twisting-0000', 'Cave of Twisting Shadows', 'magic', 6, 767, 'Greater Alps', 'medium', 'Un lieu d''ascétisme et de méditation ésotérique pure. Entièrement souterraine, plongée dans un silence religieux, l''alliance abrite les mages Criamon qui cherchent à percer l''Énigme du temps et à briser le cycle infini des souffrances du monde.', 1, 'Maison Criamon', 'Hiver', 'Un réseau labyrinthique de cavernes souterraines totalement obscures sous les sommets alpins (Canton des Grisons, Suisse).', '46.8000° N, 9.5000° E', 'Les esprits les plus énigmatiques, ascétiques et lourdement tatoués de motifs mystiques de la Maison Criamon.', 'Aucun compagnon mondain classique. Quelques rares mystiques, ascètes et ermites sourds-muets partageant la vie contemplative des mages.', 'Serviteurs et gardes observant un mutisme total, dont beaucoup présentent des altérations physiques ou des marques cutanées bizarres nées de l''exposition prolongée aux distorsions de l''Enigme.', 'L''Ombre Mouvante (8 pions Vim), Le Puits des Murmures (6 pions Mentem).', 'Cellules de pierre brute taillées dans la roche, sans fenêtres. Équipés de la Vertu Isolé du Monde et du Défaut Sombre, parfaits pour la méditation interne et l''étude des concepts abstraits, mais inadaptés aux manipulations physiques d''ingrédients.', 'Textes hautement cryptiques, diagrammes labyrinthiques indéchiffrables pour les non-initiés, et grimoires anciens centrés sur la nature du temps, l''Énigme hermétique et le dépassement des limites humaines.'),
('cov-coeris-0000', 'Coeris', 'magic', 6, 767, 'Transylvania', 'large', 'Le quartier général de la Maison la plus disciplinée et hiérarchisée de l''Ordre. Conçue comme un castrum romain adapté à la guerre magique, la citadelle fonctionne avec une rigueur toute militaire, planifiant la défense de l''Ordre contre les menaces orientales.', 1, 'Maison Tremere', 'Automne', 'Une citadelle de granit noir imprenable construite sur les crêtes escarpées des montagnes de Făgăraș (Carpates, Roumanie).', '45.6500° N, 24.6000° E', 'Primus Poenitus (Tremere, Stratège suprême de la Maison), Archimage Txeru, et l''état-major hermétique.', 'Logisticiens militaires, tacticiens de terrain, officiers de liaison, diplomates rigoureux et Redcaps assermentés soumis au salut militaire.', 'Le Turb le plus puissant et redoutable d''Europe, organisé en Vexillations (légions) comprenant de l''infanterie lourde blindée, des archers d''élite et des ingénieurs de siège entraînés à appuyer la magie de destruction.', 'La Gorge des Serments (12 pions Rego), La Fourrure des Alphas (8 pions Muto), Le Sol des Martyrs (5 pions Perdo).', 'À l''inverse de l''anarchie créative habituelle, les laboratoires de Coeris sont uniformisés. Construits selon un plan architectural identique, ils privilégient les Vertus Sécurité Supérieure et Ordre Rigide. Cela élimine les risques d''accidents magiques (Botch) mais limite les élans d''expérimentation sauvage.', 'Hautement rationalisée et d''accès strictement réglementé par la hiérarchie. La bibliothèque met exclusivement l''accent sur l''Art du Rego, la magie de destruction élémentaire et la logistique militaire. Elle possède la collection la plus complète de Casting Tablets rituelles d''Europe.'),
('cov-kastellon-0000', 'Kastellon', 'magic', 5, 1130, 'Transylvania', 'medium', 'Un avant-poste militaire avancé conçu par la Maison Tremere pour surveiller les mouvements des tribus païennes et contenir l''incursion de monstres ou de sorciers slaves non-alignés à l''Ordre.', 1, NULL, 'Été', 'Un château fortifié gardant un col stratégique face aux plaines sauvages des Carpates orientales (Roumanie).', '46.5000° N, 26.0000° E', 'Trois mages de guerre de la Maison Tremere spécialisés dans les barrières magiques et la détection à longue distance.', 'Maîtres d''armes, ingénieurs en fortifications laïques et intendants militaires veillant à l''approvisionnement des stocks de siège.', 'Troupes de choc lourdes et cavalerie légère entraînés à patrouiller en territoire hostile et à faire face au surnaturel.', 'Les Portes de Kastellon (7 pions Rego), Les Brasiers de Guet (5 pions Ignem), Les Sabots de Guerre (3 pions Animal).', 'Aménagés dans les casemates de la forteresse. Robustes, fonctionnels, équipés de la Vertu Fortifié, capables de résister à un assaut physique direct pendant que le mage prépare ses contre-sorts.', 'Manuels de fortification, grimoires de combat tactique, recueils de sorts de zone et études approfondies sur les créatures magiques des forêts slaves.'),
('cov-blackthorn-0000', 'Blackthorn', 'magic', 4, 960, 'Stonehenge', 'medium', 'Un bastion rigide, austère et paranoïaque. Ayant longtemps exercé une hégémonie politique agressive sur le tribunal de Stonehenge, Blackthorn voit aujourd''hui ses ressources s''épuiser et son autorité contestée par de jeunes alliances printanières dynamiques.', 1, NULL, 'Hiver', 'Une forteresse de pierre sombre bâtie au cœur des forêts denses des Black Mountains (Pays de Galles actuel).', '51.9000° N, -3.1000° W', 'Une coterie d''archimages conservateurs et isolationnistes appartenant principalement aux Maisons Ex Miscellanea et Tremere.', 'Espions gallois, agents d''influence et diplomates habiles infiltrés dans les cours des barons anglais de la Marche pour manipuler les affaires mondaines.', 'Une garnison vivant dans des casernements souterrains sous la forteresse, réputée pour ses archers gallois à arc long et ses tirailleurs de nuit experts en guérilla forestière.', 'Les Épines de l''Aubépine (8 pions Rego), Les Eaux Sombres (5 pions Perdo), La Brume des Morts (3 pions Vim).', 'Anciens, froids et humides. Présentent souvent le Défaut Ancien et Courants d''Air, mais disposent de remarquables Défenses Magiques Intégrées empêchant toute localisation ou scrutation magique à distance par des rivaux.', 'Importante collection sur le droit coutumier gallois, la géomancie des lignes de force (Ley Lines) d''Angleterre, et des traités avancés d''art du Rego noir et de manipulation des esprits terrestres.'),
('cov-pythagoranis-0000', 'Schola Pythagoranis', 'magic', 4, 1080, 'Stonehenge', 'medium', 'Une alliance académique et scientifique d''élite. Ses mages rejettent l''isolationnisme et étudient les liens profonds entre les mathématiques grecques, l''astronomie arabe et les fondements de la théorie magique hermétique, vivant à proximité immédiate des érudits mondains.', 1, NULL, 'Été', 'Une grande demeure fortifiée en pierre située à la périphérie immédiate de la ville universitaire de Cambridge (Angleterre).', '52.2000° N, 0.1200° E', 'Mages mathématiciens, géomètres et astronomes appartenant principalement aux Maisons Bonisagus et Jerbiton.', 'Calculateurs, astrologues universitaires, architectes laïques et philosophes de la nature enseignant ou étudiant à Cambridge.', 'Gardes de domaine calmes, stricts et extrêmement disciplinés, entraînés à maintenir un périmètre de silence absolu autour des installations scientifiques sans perturber le calme des études.', 'L''Astrolabe de Marbre (8 pions Terram), Le Compas d''Argent (6 pions Rego).', 'Salles d''étude lumineuses équipées de grands instruments de mesure, de cadrans et de lentilles de verre. Dotés de la Vertu Ordre Rigide et de Matériel de Précision, offrant des bonus substantiels pour le calcul de formules magiques complexes.', 'Excellente collection de mathématiques arabes, de traités d''astronomie d''Al-Andalus, de géométrie sacrée d''Euclide et de Summae de premier ordre en Terram et Rego.'),
('cov-horsinglas-0000', 'Horsinglas', 'magic', 5, 950, 'Loch Leglean', 'medium', 'Le cœur politique et spirituel du tribunal d''Écosse. Le fort s''intègre parfaitement aux structures rocheuses et est le point de ralliement des mages d''Ex Miscellanea qui défendent l''indépendance culturelle et magique des Highlands face aux influences anglaises.', 1, NULL, 'Automne', 'Un fort de pierre circulaire écossais (Broch) érigé sur un promontoire rocheux isolé des Highlands (Écosse).', '57.0000° N, -4.5000° W', 'Mages de la Maison Ex Miscellanea issus des anciennes lignées traditionnelles de sorciers écossais (Gruagach).', 'Chefs de clans écossais alliés, bardes locaux, gardiens des traditions orales celtes et guérisseurs traditionnels.', 'Guerriers des Highlands féroces et passionnés, vêtus de tartans aux couleurs de l''alliance, experts en embuscades, en pistage et en mêlée sauvage dans les tourbières.', 'Les Cornes de Cerf (8 pions Animal), La Bruyère Sacrée (6 pions Herbam), Les Pierres de Foudre (4 pions Rego).', 'Ateliers rustiques chauffés par de grands foyers ouverts. Ils possèdent le Défaut Équipement Rudimentaire pour les standards hermétiques classiques, mais bénéficient de la Vertu Esprits Locaux Alliés, permettant d''invoquer facilement l''aide d''entités de la nature.', 'Essentiellement composée de traditions orales transcrites avec peine sur des vélins grossiers, de poèmes de pouvoir et d''études approfondies sur les esprits de la nature et les rituels de métamorphose animale.'),
('cov-jaferia-0000', 'Jaferia', 'magic', 4, 1085, 'Iberia', 'medium', 'Un joyau d''architecture doté de patios en stuc, de fontaines et de cours ombragées. L''alliance est un modèle de tolérance et de synthèse intellectuelle, où mages chrétiens et musulmans collaborent pour fusionner la magie hermétique avec l''alchimie et l''astronomie arabes.', 1, NULL, 'Été', 'Un somptueux palais fortifié d''architecture maure situé dans les collines arides près de Saragosse (Aragon / Al-Andalus).', '41.6500° N, -0.8800° W', 'Flambeau d''origine maure, spécialistes de l''alchimie et mages Jerbiton andalous œuvrant pour la coexistence culturelle.', 'Traducteurs de l''école de Tolède, astronomes, érudits bilingues (arabe/latin), médecins et diplomates discrets des cours princières.', 'Cavaliers légers d''élite et éclaireurs d''inspiration Almogavres, d''une rapidité et d''une mobilité redoutables dans les environnements arides et montagneux.', 'L''Huile d''Olive d''Or (6 pions Ignem), Le Cadran Solaire de Stuc (5 pions Creo), Le Sable Doré (5 pions Vim).', 'Magnifiques ateliers alchimiques, vastes, aérés et dotés de grands instruments d''astronomie en bronze. Équipés de la Vertu Laboratoire d''Alchimiste Supérieur, offrant de grands bonus pour la transmutation des métaux et la création de potions.', 'Exceptionnel fonds d''alchimie arabe, de traités de médecine d''Avicenne, de philosophie d''Averroès et de Summae de premier ordre en Ignem, Muto et Rego, traduits en latin médiéval.'),
('cov-ashenrise-0000', 'Ashenrise', 'magic', 4, 1014, 'Hibernia', 'medium', 'Un sanctuaire forestier où les structures en bois et en terre respectent les flux d''énergie de l''île. L''alliance fonctionne selon le droit coutumier irlandais et sert de cour de justice hermétique pour régler les litiges entre lignées magiques locales.', 1, NULL, 'Été', 'Établie à proximité des collines sacrées de Tara, dissimulée au cœur de la forêt dense d''Ollamh (Irlande actuelle).', '53.5700° N, -6.6100° W', 'Juges hermétiques (Brehons) et mages de la Maison Ex Miscellanea formés à la tradition des maîtres-savants celtes.', 'Historiens claniques, spécialistes des anciennes lois coutumières de Brehon et poètes rituels (Fili) respectés par la population locale.', 'Guerriers légers Kerns irlandais, extrêmement mobiles, armés de javelots et de longues dagues, redoutables pour mener une guérilla dans les marécages et les forêts denses.', 'Le Frêne Sacré d''Ashenrise (6 pions Herbam), Les Pierres d''Ogham (5 pions Rego), L''Eau de la Boyne (3 pions Muto).', 'Intégrés dans des arbres creux ou des structures de terre sacrée semi-enterrées. Dotés de la Vertu Harmonie Naturelle, ce qui facilite grandement l''invention de sorts de métamorphose et de manipulation végétale.', 'Consacrée à la préservation des généalogies d''Hibernia, aux recueils des lois de Brehon et aux magies traditionnelles de transformation de la matière (Muto) et du Royaume Animal.'),
('cov-favras-0000', 'Favras', 'magic', 5, 800, 'Thèbes', 'medium', 'Une citadelle de marbre blanc d''inspiration néoclassique byzantine. Favras est un centre de haute théurgie et d''études juridiques, maintenant des liens étroits mais discrets avec l''administration impériale de Constantinople.', 1, NULL, 'Automne', 'Construite au sommet d''un éperon rocheux escarpé de la péninsule de Chalcidique, surplombant la mer Égée (Grèce actuelle, Empire Byzantin).', '40.3000° N, 23.8000° E', 'Théurges grecs, invocateurs d''esprits planétaires et mages légalistes de la Maison Guernicus.', 'Scribes impériaux byzantins en rupture de ban, juristes éminents, astronomes et diplomates infiltrés dans la bureaucratie de l''Empire.', 'Une force d''infanterie lourde et rigide inspirée de la Garde Varègue, armée de grandes haches de combat à deux mains, de lourds boucliers ronds et de cuirasses de fer.', 'L''Encens d''Athéna (8 pions Vim), Les Lauriers de Favras (6 pions Rego), Les Olives d''Argent (6 pions Creo).', 'Vastes salles rituelles dallées de marbre, ornées de mosaïques protectrices complexes et de cercles d''invocation incrustés de nacre. Équipés de la Vertu Cercle d''Invocation Permanent, offrant un bonus de +4 pour l''invocation et le contrôle des esprits.', 'Immense collection de droit hermétique, d''archives juridiques du Tribunal de Thèbes, de parchemins antiques de théurgie néoplatonicienne et de Summae de premier ordre en Rego et Vim.'),
('cov-krasnorechye-0000', 'Krasnorechye', 'magic', 4, 1115, 'Novgorod', 'medium', 'Une grande colonie fortifiée en bois de rondins (style Ostrog), entourée d''une palissade défensive hérissée de pieux. C''est un havre de sécurité au milieu d''une nature immense et hostile, habitée par des esprits païens farouches.', 1, NULL, 'Été', 'Sur les berges isolées d''une rivière sauvage serpentant au cœur de la taïga profonde, au nord-est de la Principauté de Novgorod (Russie actuelle).', '58.5000° N, 32.3000° E', 'Sorciers d''Ex Miscellanea perpétuant les traditions magiques des chamans et prêtres russes slaves (Volkhv).', 'Chasseurs de fourrures sibériens, trappeurs chevronnés, guides des forêts et boyards déchus vivant en marge du pouvoir des princes mondains.', 'Archers montés émérites et éclaireurs des neiges équipés de lourdes pelisses, habitués à survivre aux hivers polaires et à traquer les monstres de la taïga.', 'Les Fourrures d''Ours (6 pions Animal), La Glace de la Rivière Noire (5 pions Auram), Les Pierres de Foudre Slaves (4 pions Terram).', 'Isolés par de lourdes fourrures d''animaux fixées aux parois de rondins, chauffés par d''immenses poêles en brique magiques. Ils possèdent la Vertu Chauffage Magique (indispensable pour touché par le gel des ingrédients) mais souffrent du Défaut Rustique.', 'Essentiellement composée de parchemins en vieux slave et en grec médiéval, centrés sur la théurgie slave, le contrôle des esprits de la forêt (Leshy), la météo (Auram) et l''art de l''Animal.'),
('cov-acre-0000', 'Acre (Crusader''s Edge)', 'magic', 3, 1192, 'The Levant', 'medium', 'Un réseau souterrain secret, confinant ses membres sous la ville de surface. C''est un avant-poste hermétique brûlant, vivant sous la menace constante du Dominion divin de l''Église chrétienne et de l''Islam mondain, servant de base d''exploration pour les secrets antiques enfouis dans le désert.', 1, NULL, 'Printemps / Été', 'Dans les sous-sols fortifiés, les citernes cachées et les cryptes secrètes de la cité fortifiée de Saint-Jean-d''Acre (Levant).', '32.9200° N, 35.0700° E', 'Mages Flambeau croisés (militants) et spécialistes Jerbiton œuvrant comme diplomates et intermédiaires culturels secrets avec les magiciens orientaux (Sahirs).', 'Chevaliers laïques en rupture de ban avec leurs ordres templiers ou hospitaliers, marchands vénitiens et guides bédouins du désert syrien.', 'Une garnison de sergents d''armes croisés lourdement armés et de mercenaires syriens, entraînés à défendre les accès souterrains contre les intrusions mondaines ou les créatures du désert.', 'Le Sang des Croisés (5 pions Ignem), Les Reliques du Désert (4 pions Rego), L''Huile Sacrée d''Acre (3 pions Vim).', 'Aménagés dans d''anciennes citernes romaines ou des tombes juives souterraines. Confinés, ils possèdent le Défaut Étroit et Sans Fenêtre, mais bénéficient de la Vertu Sécurité Supérieure contre la détection divine ou spirituelle extérieure.', 'Petite mais précieuse collection de parchemins et de codex décrivant les techniques des magiciens d''Orient (Sahirs), la structure des esprits du désert (Djinns) et des grimoires tactiques d''Ignem et de Rego.')
